class TestSafeInt:
    def test_valid_int(self):
        assert _safe_int(5) == 5
        assert _safe_int(0) == 0
        assert _safe_int(-10) == -10

    def test_valid_float_to_int(self):
        assert _safe_int(5.7) == 5
        assert _safe_int(5.0) == 5

    def test_valid_string_to_int(self):
        assert _safe_int("42") == 42
        assert _safe_int("-5") == -5

    def test_none_returns_default(self):
        assert _safe_int(None) == 0
        assert _safe_int(None, default=99) == 99

    def test_nan_returns_default(self):
        assert _safe_int(float('nan')) == 0
        assert _safe_int(np.nan) == 0
        assert _safe_int(pd.NA) == 0
        assert _safe_int(np.nan, default=42) == 42

    def test_nat_returns_default(self):
        assert _safe_int(pd.NaT) == 0
        assert _safe_int(pd.NaT, default=10) == 10

    def test_invalid_string_returns_default(self):
        assert _safe_int("abc") == 0
        assert _safe_int("abc", default=5) == 5
        assert _safe_int("") == 0

    def test_invalid_type_returns_default(self):
        assert _safe_int([1, 2, 3]) == 0
        assert _safe_int({'a': 1}) == 0


class TestSafeFloat:
    def test_valid_float(self):
        assert _safe_float(5.5) == 5.5
        assert _safe_float(0.0) == 0.0
        assert _safe_float(-3.14) == -3.14

