class TestSafeStr:
    def test_valid_string(self):
        assert _safe_str("hello") == "hello"
        assert _safe_str("") == ""

    def test_int_to_string(self):
        assert _safe_str(42) == "42"

    def test_float_to_string(self):
        assert _safe_str(3.14) == "3.14"

    def test_none_returns_default(self):
        assert _safe_str(None) == ""
        assert _safe_str(None, default="N/A") == "N/A"

    def test_nan_returns_default(self):
        assert _safe_str(float('nan')) == ""
        assert _safe_str(np.nan) == ""
        assert _safe_str(pd.NA) == ""
        assert _safe_str(np.nan, default="unknown") == "unknown"

    def test_nat_returns_default(self):
        assert _safe_str(pd.NaT) == ""
        assert _safe_str(pd.NaT, default="no time") == "no time"


