class TestGetRaceResults:
    def _create_mock_session(self, results_data):
        mock_session = Mock()
        mock_session.results = pd.DataFrame(results_data)
        mock_session.event.get.side_effect = lambda k, default=None: {
            'EventDate': Mock(year=2024),
            'RoundNumber': 5
        }.get(k, default)
        return mock_session

    @patch('src.f1_data._get_wdc_standings')
    @patch('src.f1_data.get_driver_colors')
    def test_basic_race_results(self, mock_colors, mock_standings):
        mock_colors.return_value = {
            'VER': (255, 0, 0),
            'NOR': (255, 135, 0),
            'LEC': (220, 0, 0)
        }
        mock_standings.return_value = {'VER': 1, 'NOR': 2, 'LEC': 3}

        results_data = {
            'Abbreviation': ['VER', 'NOR', 'LEC'],
            'Position': [1, 2, 3],
            'FullName': ['Max Verstappen', 'Lando Norris', 'Charles Leclerc'],
            'TeamName': ['Red Bull Racing', 'McLaren', 'Ferrari'],
            'GridPosition': [1, 3, 2],
            'Points': [25.0, 18.0, 15.0],
            'Time': [timedelta(hours=1, minutes=30, seconds=45.123), 
                     timedelta(seconds=5.432),
                     timedelta(seconds=10.876)],
            'Status': ['Finished', 'Finished', 'Finished'],
            'FastestLap': [1, 2, 3]
        }

        mock_session = self._create_mock_session(results_data)
        result = get_race_results(mock_session)

        assert len(result) == 3

        # Check P1
        p1 = result[0]
        assert p1['code'] == 'VER'
        assert p1['position'] == 1
        assert p1['name'] == 'Max Verstappen'
        assert p1['team'] == 'Red Bull Racing'
        assert p1['grid_pos'] == 1
        assert p1['points'] == 25
        assert p1['fastest_lap'] == True  # FastestLap rank 1 = has fastest lap
        assert p1['wdc_position'] == 1
        assert p1['race_time_secs'] is not None
        assert p1['color'] == (255, 0, 0)

        # Check P2
        p2 = result[1]
        assert p2['code'] == 'NOR'
        assert p2['position'] == 2
        assert p2['fastest_lap'] == False  # FastestLap rank 2 = not fastest
        assert p2['wdc_position'] == 2

