            'Position': [1],
            'FullName': ['Max Verstappen'],
            'TeamName': ['Red Bull'],
            'GridPosition': [1],
            'Points': [25.0],
            'Time': [race_time],
            'Status': ['Finished'],
            'FastestLap': [1]
        }

        mock_session = self._create_mock_session(results_data)
        result = get_race_results(mock_session)

        assert abs(result[0]['race_time_secs'] - expected_secs) < 0.001


